//! Hermes Universal — Tauri v2 entrypoint (shared by desktop dev and the mobile
//! Android/iOS targets). `run()` is the mobile entry point; the Android project
//! generated by `tauri android init` calls into it.
//!
//! All network traffic runs in Rust (`transport`), not the webview — see
//! `transport.rs`. The frontend drives it over IPC and reuses the JS
//! `JsonRpcGatewayClient` via an IPC-backed WebSocket.

mod oauth;
mod transport;

use oauth::{oauth_login, oauth_logout, oauth_status};
use transport::{
    cookies_export, cookies_import, http_request, ws_close, ws_open, ws_send, TransportState,
};

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    tauri::Builder::default()
        .plugin(tauri_plugin_os::init())
        .plugin(tauri_plugin_keyring::init())
        .plugin(tauri_plugin_opener::init())
        .plugin(tauri_plugin_haptics::init())
        .plugin(tauri_plugin_dialog::init())
        .plugin(tauri_plugin_fs::init())
        .plugin(tauri_plugin_notification::init())
        .manage(TransportState::new())
        .invoke_handler(tauri::generate_handler![
            http_request,
            ws_open,
            ws_send,
            ws_close,
            oauth_login,
            oauth_status,
            oauth_logout,
            cookies_export,
            cookies_import
        ])
        .run(tauri::generate_context!())
        .expect("error while running Hermes Universal");
}
